import hashlib
import json
from pathlib import Path


def verify_docstring_accuracy(
    docstring: str,
    source_code: str,
) -> dict:
    """
    Ask the model to check whether a docstring accurately reflects the source code.
    Returns {accurate: bool, issues: [str], confidence: float}.
    """
    prompt = (
        "Compare this docstring against the source code. "
        "Report any inaccuracies: wrong parameter names, incorrect types, "
        "behavior described that the code does not implement, missing parameters, "
        "or incorrect return type / description.\n\n"
        f"DOCSTRING:\n{docstring}\n\nSOURCE CODE:\n{source_code}\n\n"
        'Return JSON: {"accurate": bool, "issues": [strings], "confidence": 0.0-1.0}. JSON only.'
    )
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(response.content[0].text)


class DocStalenessTracker:
    """
    Track source file hashes and re-generate documentation when source changes.
    Persists hash state to disk between runs.
    """
    def __init__(self, state_file: str = ".doc_hashes.json") -> None:
        self.state_file = Path(state_file)
        self._hashes: dict[str, str] = self._load()

    def _load(self) -> dict:
        if self.state_file.exists():
            return json.loads(self.state_file.read_text())
        return {}

    def _save(self) -> None:
        self.state_file.write_text(json.dumps(self._hashes, indent=2))

    def _hash(self, content: str) -> str:
        return hashlib.sha256(content.encode()).hexdigest()[:16]

    def needs_update(self, source_path: str, source_content: str) -> bool:
        """Return True if the source has changed since the last doc generation."""
        new_hash = self._hash(source_content)
        return self._hashes.get(source_path) != new_hash

    def mark_updated(self, source_path: str, source_content: str) -> None:
        """Record that documentation was generated for this source version."""
        self._hashes[source_path] = self._hash(source_content)
        self._save()


def regenerate_stale_docs(
    source_files: list[str],
    tracker: DocStalenessTracker,
    style: str = "google",
) -> dict[str, dict[str, str]]:  # {file: {func_name: docstring}}
    results = {}
    for path in source_files:
        content = Path(path).read_text()
        if tracker.needs_update(path, content):
            print(f"Regenerating docs for {path} (source changed)")
            # generate_docstrings_for_file would call document_module(path)
            # (implementation shown in section 1)
            # results[path] = asyncio.run(document_module(path, style=style))
            tracker.mark_updated(path, content)
        else:
            print(f"Skipping {path} (unchanged)")
    return results
